1	type Item = {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	};
7	type QuoteStep = { op: "quote"; items: Item[] };
8	type ClaimStep = {
9	  op: "claim";
10	  policy: number;
11	  incident: {
12	    cause: string;
13	    damages: { itemType: string; amount: number }[];
14	  };
15	};
16	type Step = QuoteStep | ClaimStep;
17	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
18	
19	const FIRST_INSURANCE_MULTIPLIER = 1.1;
20	const POST_FIRST_CONTRACT_MULTIPLIER = 0.85;
21	const CURSED_MULTIPLIER = 1.5;
22	const HIGH_ENCHANTMENT_MULTIPLIER = 1.3;
23	const LOYALTY_MULTIPLIER = 0.8;
24	const LOYALTY_YEARS_THRESHOLD = 2;
25	const ADMIN_FEE = 5;
26	const DEDUCTIBLE = 100;
27	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
28	const HIGH_ENCHANTMENT_REIMBURSEMENT_FRACTION = 0.5;
29	
30	// Three alike pieces of a "building-block" item (rune, moonstone, ‚Ä¶) pool
31	// to a single unit priced at this fixed tier, irrespective of the per-piece
32	// BASE_PRICE. The tier coincidentally equals amulet's base price today but
33	// is conceptually a separate pricing rule from the per-item ladder.
34	const BUILDING_BLOCK_PRICE = 60;
35	
36	const BASE_PRICE: Record<string, number> = {
37	  sword: 100,
38	  staff: 80,
39	  amulet: 60,
40	  potion: 40,
41	  rune: 25,
42	  moonstone: 25,
43	};
44	
45	const POOLED_TYPES = new Set(["rune", "moonstone"]);
46	
47	function itemModifierMultiplier(item: Item): number {
48	  const cursed = item.cursed ? CURSED_MULTIPLIER : 1;
49	  const highEnchantment =
50	    (item.enchantment ?? 0) >= 5 ? HIGH_ENCHANTMENT_MULTIPLIER : 1;
51	  return cursed * highEnchantment;
52	}
53	
54	// MHPCO always rounds the euro value of a discounted/loaded price upward
55	// (in the office's favour). The toFixed(10) step strips IEEE-754 drift so
56	// values that are mathematically integer (e.g. 100 √ó 1.10 = 110) don't get
57	// bumped up a euro by a 110.00000000000001 representation.
58	function ceilInMhpcoFavor(value: number): number {
59	  return Math.ceil(Number(value.toFixed(10)));
60	}
61	
62	// Sum of per-item base prices (with item-attribute multipliers applied)
63	// for a single quote. Building-block items (rune today, moonstone in cycle
64	// 13) are pooled in groups of three at BUILDING_BLOCK_PRICE; leftovers fall
65	// back to the per-piece BASE_PRICE.
66	function quoteItemsSubtotal(items: Item[]): number {
67	  let subtotal = 0;
68	  const pooledCounts = new Map<string, number>();
69	  for (const item of items) {
70	    if (POOLED_TYPES.has(item.type)) {
71	      pooledCounts.set(item.type, (pooledCounts.get(item.type) ?? 0) + 1);
72	    } else {
73	      subtotal += BASE_PRICE[item.type] * itemModifierMultiplier(item);
74	    }
75	  }
76	  for (const [type, count] of pooledCounts) {
77	    const buildingBlocks = Math.floor(count / 3);
78	    const loose = count % 3;
79	    subtotal += buildingBlocks * BUILDING_BLOCK_PRICE + loose * BASE_PRICE[type];
80	  }
81	  return subtotal;
82	}
83	
84	// Reimbursement percentage by item attribute (dragon material always wins
85	// today; enchantment 9 and other tiers will join here in later cycles).
86	function itemReimbursementFraction(item: Item | undefined): number {
87	  if (item?.material === "dragon") return 1;
88	  if ((item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD)
89	    return HIGH_ENCHANTMENT_REIMBURSEMENT_FRACTION;
90	  return 0;
91	}
92	
93	// Look up the insured item on the originating quote (referenced by
94	// `claimStep.policy` as an index into the step list), compute the
95	// reimbursement for the incident, subtract the flat deductible, and floor
96	// the payout at zero.
97	function claimPayout(claimStep: ClaimStep, allSteps: Step[]): { payout: number } {
98	  const policyStep = allSteps[claimStep.policy] as QuoteStep;
99	  const damage = claimStep.incident.damages[0];
100	  const item = policyStep.items.find((i) => i.type === damage.itemType);
101	  const reimbursement = damage.amount * itemReimbursementFraction(item);
102	  return { payout: Math.max(0, reimbursement - DEDUCTIBLE) };
103	}
104	
105	export function runScenario(scenario: unknown): unknown {
106	  const { customer, steps } = scenario as Scenario;
107	  const loyaltyMultiplier =
108	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_MULTIPLIER : 1;
109	  const results = steps.map((step, quoteIndex) => {
110	    if (step.op === "claim") return claimPayout(step, steps);
111	    const itemsSubtotal = quoteItemsSubtotal(step.items);
112	    const contractMultiplier =
113	      quoteIndex === 0 ? FIRST_INSURANCE_MULTIPLIER : POST_FIRST_CONTRACT_MULTIPLIER;
114	    const premium =
115	      ceilInMhpcoFavor(itemsSubtotal * loyaltyMultiplier * contractMultiplier) +
116	      ADMIN_FEE;
117	    return { premium };
118	  });
119	  return { results };
120	}
