function claimPayout(claimStep: ClaimStep, allSteps: Step[]): { payout: number } {
  const policyStep = allSteps[claimStep.policy] as QuoteStep;
  let reimbursement = 0;
  for (const damage of claimStep.incident.damages) {
    const item = policyStep.items.find((i) => i.type === damage.itemType);
    reimbursement += damage.amount * itemReimbursementFraction(item);
  }
  return { payout: Math.max(0, reimbursement - DEDUCTIBLE) };
}
